-- Generated from scripts/wc2026-schedule.json. Paste into Supabase SQL editor.
-- Idempotent: re-running is safe.

begin;

-- Teams (48)
on conflict (name) do update set group_label = excluded.group_label;

-- Players (Golden Boot shortlist)

-- Matches (104) — upsert by fifa_match_number
on conflict (fifa_match_number) do update set
  stage = excluded.stage, group_label = excluded.group_label,
  team_a_id = excluded.team_a_id, team_b_id = excluded.team_b_id,
  placeholder_a = excluded.placeholder_a, placeholder_b = excluded.placeholder_b,
  kickoff_at = excluded.kickoff_at, match_order = excluded.match_order,
  stadium = excluded.stadium, city = excluded.city;

-- Tournament config (dates derived from the schedule)
update public.tournament_config set name = 'FIFA World Cup 2026', starts_at = '2026-06-11T19:00:00Z', group_stage_ends_at = '2026-06-28T19:00:00Z' where id = 1;

commit;
